from collections import deque

class Solution:
    def maxSlidingWindow(self, nums: list[int], k: int) -> list[int]:
        if not nums or k == 0:
            return []

        q = deque()  # 存放下标，对应值单调递减
        result = []

        for i in range(len(nums)):
            # 移除队尾小于等于当前值的元素
            while q and nums[q[-1]] <= nums[i]:
                q.pop()

            q.append(i)

            # 移除窗口外的元素
            if q[0] <= i - k:
                q.popleft()

            # 记录结果
            if i >= k - 1:
                result.append(nums[q[0]])

        return result
